#!/usr/bin/env bash
set -e
DEST="$HOME/promptdeed"
PORT="${PROMPTDEED_PORT:-8765}"

echo ""
echo "Installing Promptdeed to $DEST..."
mkdir -p "$DEST" && cd "$DEST"

cat <<'BLOB_EOF' | base64 -d | tar xzf -

BLOB_EOF

echo ""
echo "Promptdeed installed."

if ! command -v ollama >/dev/null 2>&1; then
  echo ""
  echo "Install Ollama for local AI? (y/n)"
  read -r ans
  if [ "$ans" = "y" ] || [ "$ans" = "Y" ]; then
    curl -fsSL https://ollama.com/install.sh | sh
  fi
fi

echo ""
echo "================================================"
echo "  Open: http://localhost:$PORT"
echo "  Ctrl+C to stop"
echo "================================================"
echo ""

cd "$DEST" && python3 -m http.server "$PORT"
